    public static function getLogs($range = 1440, $step = 60): object {
        $con = \Doctrine_Manager::connection()->getDbh();
        $offset = new DateTime();
        $offset->sub(new DateInterval("PT{$range}M"));
        $offsetTime = $offset->format('Y-m-d H:i:s');

        $sql = <<<SQL
SELECT
  - TIMESTAMPDIFF (MINUTE, `l`.`datetimestart`, "$offsetTime") AS `left`,
  - TIMESTAMPDIFF (MINUTE,  IFNULL(`l`.`datetimestop`, `l`.`datetimestart`), "$offsetTime") AS `right`,
  `l`.`datetimestart` AS `start`,
  `l`.`datetimestop` AS `stop`,
  TIMESTAMPDIFF (SECOND, `l`.`datetimestart`, IFNULL(`l`.`datetimestop`, `l`.`datetimestart`)) AS `runtime`,
  `l`.`status`,
  `l`.`message`,
  IFNULL(`c`.`name`, `c`.`script`) AS `name`,
  `c`.`id` AS `id`
FROM `common__model__cron_log` `l`
    INNER JOIN `common__model__cron` `c` ON (`l`.`cron_id` = `c`.`id`)
WHERE `l`.`datetimestart` >  "$offsetTime"
ORDER BY 1, 2 DESC;
SQL;

        $arr = $con->query($sql)->fetchAll(\PDO::FETCH_OBJ);

        $final = array();
        $middle = array();

        if (is_array($arr) && count($arr) > 1) {
            $level = 0;
            do {
                $arr[0]->top = $level;
                $arr[0]->width = $arr[0]->right - $arr[0]->left + 4;
                $arr[0]->before = gmdate("H:i:s", $arr[0]->before ?? 0);
                $arr[0]->runtime = gmdate("H:i:s", $arr[0]->runtime ?? 0);
                $final[] = $arr[0];
                $maxRight = $arr[0]->right + 5;
                for ($i = 1; $i < count($arr) - 1; $i++) {
                    if ($arr[$i]->left > $maxRight) {
                        $arr[$i]->top = $level;
                        $arr[$i]->width = $arr[$i]->right - $arr[$i]->left + 4;
                        $arr[$i]->before = gmdate("H:i:s", $arr[$i]->before ?? 0);
                        $arr[$i]->runtime = gmdate("H:i:s", $arr[$i]->runtime ?? 0);
                        $final[] = $arr[$i];
                        $maxRight = $arr[$i]->right + 4;
                    } else {
                        $middle[] = $arr[$i];
                    }
                }
                if (count($middle)) {
                    $arr = $middle;
                    $middle = array();
                    $level++;
                } else {
                    $arr = array();
                }
            } while (count($arr));
        }

        return (object)[
            'offset' => $offset->sub(new DateInterval("PT{$step}M")),
            'items' => $final,
            'range' => $range,
            'step' => $step,
            'level' => $level ?? 0,
        ];

