    /**
     * @param int $cron_ID
     * @return array|false
     */
    public static function getCronLogs(int $cron_ID): array|false
    {
        $sql = <<<SQL
SELECT
  `l`.`datetimestart` AS `DateTimeStart`,
  `l`.`datetimestop` AS `DateTimeStop`,
  `l`.`status` AS `Status`,
  `l`.`message` AS `Message`
FROM
  `common__model__cron_log` `l`
WHERE
  `l`.`cron_id` = $cron_ID
ORDER BY
  `l`.`datetimestart` DESC
SQL;

        $sth = \Doctrine_Manager::connection()->getDbh()->prepare($sql);
        $sth->execute();
        $rows = $sth->fetchAll(\PDO::FETCH_OBJ);

        return $rows;
    }

    public function getRunsInDay(): int
    {
        $sql = <<<SQL
SELECT
 COUNT(*) AS `count`
FROM
  `common__model__cron_log` `l`
WHERE
  `l`.`cron_id` = $this->ID
  AND `l`.`status` = 'OK'
  AND DATE(`l`.`datetimestart`) = CURDATE()
SQL;

        return \Doctrine_Manager::connection()->getDbh()->query($sql)->fetchColumn();
    }

    public function getLastRunRunsInDay(): int
    {
        $sql = <<<SQL
SELECT
 	MAX(`l`.`datetimestop`) AS `lastRun`
FROM
  `common__model__cron_log` `l`
WHERE
  `l`.`cron_id` = $this->ID
  AND `l`.`status` LIKE '%OK%'
GROUP BY
  `l`.`cron_id`
SQL;
        $lastRun = \Doctrine_Manager::connection()->getDbh()->query($sql)->fetchColumn();
        if (!$lastRun) {
            $date = new \DateTime();

            return $date->getTimestamp() - 60;
        }

        return strtotime($lastRun);
    }

    public static function sendMemoryUsageReport(int $minUsage = 1000): bool
    {
        $sql = <<<SQL
SELECT `amc`.`id`, `amc`.`name`, `amc`.`active`, `amc`.`cronexpression`, MAX(CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(`amcl`.`message`, 'RM: ', -1), 'MB', 1) AS DECIMAL(10,2))) AS `max_usage` 
FROM `common__model__cron_log` `amcl` 
INNER JOIN `common__model__cron` `amc` ON `amcl`.`cron_id` = `amc`.`id`
WHERE `amcl`.`message` LIKE '%[M:%' 
  AND CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(`amcl`.`message`, 'RM: ', -1), 'MB', 1) AS DECIMAL(10,2)) > ?
  AND `amcl`.`datetimestart` > DATE_SUB(NOW(), INTERVAL 1 WEEK)
GROUP BY `amcl`.`cron_id` 
ORDER BY `amcl`.`cron_id`;
SQL;

        $data = Doctrine_Manager::connection()->fetchAll($sql, [$minUsage]);

        if (!empty($data)) {
            \common\logic\Email\Email::sendCronMemoryUsageReport($data);
            return true;
        }

        return false;
    }
